cript&#34;&gt;&lt;span class=&#34;token language-javascript&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		Vue&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;config&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;productionTip &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 阻止 vue 在启动时生成生产提示。&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token class-name&#34;&gt;Vue&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;prototype&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;99&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token comment&#34;&gt;// 定义 school 组件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; school &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; Vue&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;extend&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;school&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;template&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token template-string&#34;&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&amp;lt;div&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&amp;lt;h2&gt;学校名称：&amp;lt;/h2&gt;	&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&amp;lt;h2&gt;学校地址：&amp;lt;/h2&gt;	&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&amp;lt;button @click=&#34;showX&#34;&gt;点我输出x&amp;lt;/button&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&amp;lt;/div&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;/span&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token function&#34;&gt;data&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;尚硅谷&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&lt;span class=&#34;token literal-property property&#34;&gt;address&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;北京&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;methods&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token function&#34;&gt;showX&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;this&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token comment&#34;&gt;// 创建一个 vm&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; vm &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Vue&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;el&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;#root&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;data&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token literal-property property&#34;&gt;msg&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;你好&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token literal-property property&#34;&gt;components&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;school&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token comment&#34;&gt;// 定义一个构造函数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token comment&#34;&gt;/* function Demo ()&amp;#123;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			this.a = 1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			this.b = 2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&amp;#125;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		// 创建一个 Demo 的实例对象&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		const d = new Demo ()&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		console.log (Demo.prototype) // 显示原型属性&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		console.log (d.__proto__) // 隐式原型属性&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		console.log (Demo.prototype === d.__proto__)&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;62&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;63&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		// 程序员通过显示原型属性操作原型对象，追加一个 x 属性，值为 99&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;64&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		Demo.prototype.x = 99&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;65&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;66&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		console.log (&#39;@&#39;,d) */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;67&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;68&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;单文件组件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#单文件组件&#34;&gt;#&lt;/a&gt; 单文件组件&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;单文件组件化编程就是需要创建 vue 文件 (vscode 中需要安装 Vetur 才能支持 vue 文件)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通常需要一个 App.vue 文件来管理所有的子组件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;然后需要一个 main.js 文件来绑定 App.vue, 里面需要 new 一个 Vue 对象里面直接住注册 App.vue 组件即可&lt;/p&gt;
&lt;p&gt;注册之前需要 import 文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;然后再需要一个 html 容器挂载元素即可&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;使用vue脚手架&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用vue脚手架&#34;&gt;#&lt;/a&gt; 使用 Vue 脚手架&lt;/h2&gt;
&lt;h3 id=&#34;需要注意的点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#需要注意的点&#34;&gt;#&lt;/a&gt; 需要注意的点&lt;/h3&gt;
&lt;p&gt;使用 vue-cli 脚手架，需要先下载 node, 这个可以直接去官网下载即可，下载完后可直接在 cmd 窗口查看版本，&lt;/p&gt;
&lt;p&gt;注意 npm 是 node.js 的一个包管理工具，安装完 node 这个东西自然而然也就有了&lt;/p&gt;
&lt;p&gt;后面的笔记请请查看后面的文档！！！！&lt;/p&gt;

 &lt;h1 id=&#34;vue3快速上手&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vue3快速上手&#34;&gt;#&lt;/a&gt; Vue3 快速上手&lt;/h1&gt;
&lt;p&gt;&amp;lt;img src=&amp;quot;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly91c2VyLWltYWdlcy5naXRodWJ1c2VyY29udGVudC5jb20vNDk5NTUwLzkzNjI0NDI4LTUzOTMyNzgwLWY5YWUtMTFlYS04ZDE2LWFmOTQ5ZTE2YTA5Zi5wbmc=&#34;&gt;https://user-images.githubusercontent.com/499550/93624428-53932780-f9ae-11ea-8d16-af949e16a09f.png&lt;/span&gt;&amp;quot; style=&amp;quot;width:200px&amp;quot; /&amp;gt;&lt;/p&gt;
&lt;h2 id=&#34;1vue3简介&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1vue3简介&#34;&gt;#&lt;/a&gt; 1.Vue3 简介&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;2020 年 9 月 18 日，Vue.js 发布 3.0 版本，代号：One Piece（海贼王）&lt;/li&gt;
&lt;li&gt;耗时 2 年多、&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL3Z1ZWpzL3Z1ZS1uZXh0L2dyYXBocy9jb21taXQtYWN0aXZpdHk=&#34;&gt;2600 + 次提交&lt;/span&gt;、&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL3Z1ZWpzL3JmY3MvdHJlZS9tYXN0ZXIvYWN0aXZlLXJmY3M=&#34;&gt;30 + 个 RFC&lt;/span&gt;、&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL3Z1ZWpzL3Z1ZS1uZXh0L3B1bGxzP3E9aXMlM0FwcitpcyUzQW1lcmdlZCstYXV0aG9yJTNBYXBwJTJGZGVwZW5kYWJvdC1wcmV2aWV3Kw==&#34;&gt;600 + 次 PR&lt;/span&gt;、&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL3Z1ZWpzL3Z1ZS1uZXh0L2dyYXBocy9jb250cmlidXRvcnM=&#34;&gt;99 位贡献者&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;github 上的 tags 地址：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL3Z1ZWpzL3Z1ZS1uZXh0L3JlbGVhc2VzL3RhZy92My4wLjA=&#34;&gt;https://github.com/vuejs/vue-next/releases/tag/v3.0.0&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;2vue3带来了什么&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2vue3带来了什么&#34;&gt;#&lt;/a&gt; 2.Vue3 带来了什么&lt;/h2&gt;
&lt;h3 id=&#34;1性能的提升&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1性能的提升&#34;&gt;#&lt;/a&gt; 1. 性能的提升&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;打包大小减少 41%&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;初次渲染快 55%, 更新渲染快 133%&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;内存减少 54%&lt;/p&gt;
&lt;p&gt;......&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2源码的升级&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2源码的升级&#34;&gt;#&lt;/a&gt; 2. 源码的升级&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;使用 Proxy 代替 defineProperty 实现响应式&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;重写虚拟 DOM 的实现和 Tree-Shaking&lt;/p&gt;
&lt;p&gt;......&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3拥抱typescript&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3拥抱typescript&#34;&gt;#&lt;/a&gt; 3. 拥抱 TypeScript&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Vue3 可以更好的支持 TypeScript&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;4新的特性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4新的特性&#34;&gt;#&lt;/a&gt; 4. 新的特性&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;Composition API（组合 API）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;setup 配置&lt;/li&gt;
&lt;li&gt;ref 与 reactive&lt;/li&gt;
&lt;li&gt;watch 与 watchEffect&lt;/li&gt;
&lt;li&gt;provide 与 inject&lt;/li&gt;
&lt;li&gt;......&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;新的内置组件&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Fragment&lt;/li&gt;
&lt;li&gt;Teleport&lt;/li&gt;
&lt;li&gt;Suspense&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;其他改变&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;新的生命周期钩子&lt;/li&gt;
&lt;li&gt;data 选项应始终被声明为一个函数&lt;/li&gt;
&lt;li&gt;移除 keyCode 支持作为 v-on 的修饰符&lt;/li&gt;
&lt;li&gt;......&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;一-创建vue30工程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一-创建vue30工程&#34;&gt;#&lt;/a&gt; 一、创建 Vue3.0 工程&lt;/h1&gt;
&lt;h2 id=&#34;1使用-vue-cli-创建&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1使用-vue-cli-创建&#34;&gt;#&lt;/a&gt; 1. 使用 vue-cli 创建&lt;/h2&gt;
&lt;p&gt;官方文档：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbGkudnVlanMub3JnL3poL2d1aWRlL2NyZWF0aW5nLWEtcHJvamVjdC5odG1sI3Z1ZS1jcmVhdGU=&#34;&gt;https://cli.vuejs.org/zh/guide/creating-a-project.html#vue-create&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 查看 @vue/cli 版本，确保 @vue/cli 版本在 4.5.0 以上&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;vue &lt;span class=&#34;token parameter variable&#34;&gt;--version&lt;/span&gt; 或者 vue -V&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;大写的V&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 安装或者升级你的 @vue/cli&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-g&lt;/span&gt; @vue/cli&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 创建&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;vue create vue_test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 启动&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;cd&lt;/span&gt; vue_test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; run serve&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;2使用-vite-创建&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2使用-vite-创建&#34;&gt;#&lt;/a&gt; 2. 使用 vite 创建&lt;/h2&gt;
&lt;p&gt;官方文档：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly92My5jbi52dWVqcy5vcmcvZ3VpZGUvaW5zdGFsbGF0aW9uLmh0bWwjdml0ZQ==&#34;&gt;https://v3.cn.vuejs.org/guide/installation.html#vite&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;vite 官网：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly92aXRlanMuY24=&#34;&gt;https://vitejs.cn&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;什么是 vite？—— 新一代前端构建工具。&lt;/li&gt;
&lt;li&gt;优势如下：
&lt;ul&gt;
&lt;li&gt;开发环境中，无需打包操作，可快速的冷启动。&lt;/li&gt;
&lt;li&gt;轻量快速的热重载（HMR）。&lt;/li&gt;
&lt;li&gt;真正的按需编译，不再等待整个应用编译完成。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;传统构建 与 vite 构建对比图&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&amp;lt;img src=&amp;quot;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi52aXRlanMuZGV2L2Fzc2V0cy9idW5kbGVyLjM3NzQwMzgwLnBuZw==&#34;&gt;https://cn.vitejs.dev/assets/bundler.37740380.png&lt;/span&gt;&amp;quot; style=&amp;quot;width:500px;height:280px;float:left&amp;quot; /&amp;gt;&amp;lt;img src=&amp;quot;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi52aXRlanMuZGV2L2Fzc2V0cy9lc20uMzA3MDAxMmQucG5n&#34;&gt;https://cn.vitejs.dev/assets/esm.3070012d.png&lt;/span&gt;&amp;quot; style=&amp;quot;width:480px;height:280px&amp;quot; /&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 创建工程&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; init vite-app &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;project-name&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 进入工程目录&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;cd&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;project-name&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 安装依赖&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; install&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;可简写成 &lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 运行&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;npm&lt;/span&gt; run dev   &lt;span class=&#34;token comment&#34;&gt;## 注意这里运行命令跟之前用 vue-cli 的命令不一样&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;二-常用-composition-api&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二-常用-composition-api&#34;&gt;#&lt;/a&gt; 二、常用 Composition API&lt;/h1&gt;
&lt;p&gt;官方文档: &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly92My5jbi52dWVqcy5vcmcvZ3VpZGUvY29tcG9zaXRpb24tYXBpLWludHJvZHVjdGlvbi5odG1s&#34;&gt;https://v3.cn.vuejs.org/guide/composition-api-introduction.html&lt;/span&gt;&lt;/p&gt;
&lt;h2 id=&#34;1拉开序幕的setup&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1拉开序幕的setup&#34;&gt;#&lt;/a&gt; 1. 拉开序幕的 setup&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;理解：Vue3.0 中一个新的配置项，值为一个函数。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;setup 是所有 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt;Composition API（组合 API）&amp;lt;/strong&amp;gt;&amp;lt;i style=&amp;quot;color:gray;font-weight:bold&amp;quot;&amp;gt;“ 表演的舞台 ”&amp;lt;/i&amp;gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;组件中所用到的：数据、方法等等，均要配置在 setup 中。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;setup 函数的两种返回值：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;若返回一个对象，则对象中的属性、方法，在模板中均可以直接使用。（重点关注！）&lt;/li&gt;
&lt;li&gt;&amp;lt;span style=&amp;quot;color:#aad&amp;quot;&amp;gt; 若返回一个渲染函数：则可以自定义渲染内容。（了解）&amp;lt;/span&amp;gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;注意点：(注意，目前尽量不要混用，后续生态完善了或许可以)&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;尽量不要与 Vue2.x 配置混用&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Vue2.x 配置（data、methos、computed...）中 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 可以访问到 &amp;lt;/strong&amp;gt;setup 中的属性、方法。&lt;/li&gt;
&lt;li&gt;但在 setup 中 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 不能访问到 &amp;lt;/strong&amp;gt;Vue2.x 配置（data、methos、computed...）。&lt;/li&gt;
&lt;li&gt;如果有重名，setup 优先。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;setup 不能是一个 async 函数，因为返回值不再是 return 的对象，而是 promise, 模板看不到 return 对象中的属性。（后期也可以返回一个 Promise 实例，但需要 Suspense 和异步组件的配合）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Promose 讲解&lt;/p&gt;
&lt;p&gt;promise 是一个对异步操作进行封装并返回其结果的构造函数.&lt;br /&gt;
 使代码更加简洁和避免回调地狱。&lt;br /&gt;
promise 是浏览器引擎自带的（但不是所有浏览器都支持 promise）&lt;/p&gt;
&lt;p&gt;promise 的参数是一个函数，函数里有两个参数，这两个参数也是函数。res 和 rej 这两个参数都是函数，名字随意。&lt;br /&gt;
res 是成功时的回调&lt;br /&gt;
 rej 是失败时的回调&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//res 是成功时的回调 rej 是失败时的回调&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; p &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Promise&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;res&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;rej&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;11&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;p&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码实例&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;h1&amp;gt;我是App组件&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;姓名:&amp;#123;&amp;#123;name&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;年龄:&amp;#123;&amp;#123;age&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;button @click=&amp;quot;sayHello&amp;quot;&amp;gt;说话&amp;lt;/button&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;

// import &amp;#123;h&amp;#125; from &#39;vue&#39; // 用渲染函数 才需要引用
export default &amp;#123;
  name: &#39;App&#39;,
  setup()&amp;#123;
   // 数据
   let name = &#39;张三&#39;
   let  age = 18

   // 方法
   function sayHello()&amp;#123;
    alert(`我叫$&amp;#123;name&amp;#125;，我$&amp;#123;age&amp;#125;岁了，你好啊！`) // 注意里面要被解析成变量要用模板解析的那个引号 ``
   &amp;#125;



   // 返回一个对象 返回之后才能用里面的东西 (常用)
    return &amp;#123;
     name,
     age,
    sayHello
    &amp;#125;

   // 返回一个函数 (渲染函数,了解) 它返回的东西会整个的替换掉该组件中所有的内容 
   // 用这个的话注意上面还要引用
 //  return ()=&amp;gt; h(&#39;h1&#39;,&#39;哈哈哈&#39;)
  &amp;#125;
&amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;2ref函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2ref函数&#34;&gt;#&lt;/a&gt; 2.ref 函数&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：定义一个响应式的数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法:  &lt;code&gt;const xxx = ref(initValue)&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;创建一个包含响应式数据的 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 引用对象（reference 对象，简称 ref 对象）&amp;lt;/strong&amp;gt;。&lt;/li&gt;
&lt;li&gt;JS 中操作数据：  &lt;code&gt;xxx.value&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;模板中读取数据：不需要.value，直接： &lt;code&gt;&amp;lt;div&amp;gt;&amp;#123;&amp;#123;xxx&amp;#125;&amp;#125;&amp;lt;/div&amp;gt;&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;备注：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;接收的数据可以是：基本类型、也可以是对象类型。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;基本类型的数据：响应式依然是靠 &lt;code&gt;Object.defineProperty()&lt;/code&gt;  的 &lt;code&gt;get&lt;/code&gt;  与 &lt;code&gt;set&lt;/code&gt;  完成的。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对象类型的数据：内部 &amp;lt;i style=&amp;quot;color:gray;font-weight:bold&amp;quot;&amp;gt;“ 求助 ”&amp;lt;/i&amp;gt; 了 Vue3.0 中的一个新函数 ——  &lt;code&gt;reactive&lt;/code&gt;  函数。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;h1&amp;gt;我是App组件&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;姓名:&amp;#123;&amp;#123;name&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;年龄:&amp;#123;&amp;#123;age&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;工作：&amp;#123;&amp;#123;obj.type&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;工资：&amp;#123;&amp;#123;obj.salary&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;button @click=&amp;quot;sayHello&amp;quot;&amp;gt;说话&amp;lt;/button&amp;gt;
  &amp;lt;button @click=&amp;quot;changInfo&amp;quot;&amp;gt;修改个人信息&amp;lt;/button&amp;gt;
&amp;lt;button @click=&amp;quot;changSalary&amp;quot;&amp;gt;修改工资&amp;lt;/button&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;

// import &amp;#123;h&amp;#125; from &#39;vue&#39; // 用渲染函数 才需要引用
import &amp;#123;ref&amp;#125; from &#39;vue&#39;  // 这里记得引用ref函数
export default &amp;#123;
  name: &#39;App&#39;,
  setup()&amp;#123;
   // 数据
   let name = ref(&#39;张三&#39;)  // 定义数据时候需要用ref
   let age = ref(18)
   let obj = ref(&amp;#123;
     type:&#39;前端工程师&#39;,
     salary:&#39;30k&#39;
   &amp;#125;)&#39;

   // 方法
   function sayHello()&amp;#123;
    alert(`我叫$&amp;#123;name.value&amp;#125;，我$&amp;#123;age.value&amp;#125;岁了，你好啊！`)
   &amp;#125;

   function changInfo()&amp;#123;
      name.value = &#39;李四&#39;   // 修改数据需要通过它的value值来操作
      age.value = 48 
   &amp;#125;


   function changSalary()&amp;#123;       // 修改对象的话 .value后面直接.属性就行 用ref的话
    obj.value.type = &#39;UI设计师&#39;
    obj.value.salary = &#39;60k&#39;
   &amp;#125;

   // 返回一个对象 返回之后才能用里面的东西 (常用)
   return &amp;#123;
    name,
    age,
    obj,
    sayHello,
    changInfo,
    changSalary
   &amp;#125;

   // 返回一个函数 (渲染函数,了解) 它返回的东西会整个的替换掉该组件中所有的内容 
   // 用这个的话注意上面还要引用
//    return ()=&amp;gt; h(&#39;h1&#39;,&#39;哈哈哈&#39;)
  &amp;#125;
&amp;#125;
&amp;lt;/script&amp;gt;



&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;3reactive函数不能用于基本数据类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3reactive函数不能用于基本数据类型&#34;&gt;#&lt;/a&gt; 3.reactive 函数 (不能用于基本数据类型)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;作用：定义一个 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 对象类型 &amp;lt;/strong &amp;gt; 的响应式数据（基本类型不要用它，要用 &lt;code&gt;ref&lt;/code&gt;  函数）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法： &lt;code&gt;const 代理对象= reactive(源对象)&lt;/code&gt;  接收一个对象（或数组），返回一个 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 代理对象（Proxy 的实例对象，简称 proxy 对象）&amp;lt;/strong&amp;gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;reactive 定义的响应式数据是 “深层次的”。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;内部基于 ES6 的 Proxy 实现，通过代理对象操作源对象内部数据进行操作。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码实例&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;h1&amp;gt;我是App组件&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;姓名:&amp;#123;&amp;#123;person.name&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;年龄:&amp;#123;&amp;#123;person.age&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;工作：&amp;#123;&amp;#123;person.job.type&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;工资：&amp;#123;&amp;#123;person.job.salary&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;h1&amp;gt;测试深层嵌套: &amp;#123;&amp;#123;person.job.a.b.c&amp;#125;&amp;#125;&amp;lt;/h1&amp;gt;
  &amp;lt;button @click=&amp;quot;changInfo&amp;quot;&amp;gt;修改个人信息&amp;lt;/button&amp;gt;

&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;

// import &amp;#123;h&amp;#125; from &#39;vue&#39; // 用渲染函数 才需要引用
import &amp;#123;reactive&amp;#125; from &#39;vue&#39;  // 记得引入
export default &amp;#123;
  name: &#39;App&#39;,
  setup()&amp;#123;
   // 数据
   let person  = reactive(&amp;#123;   // 全对象式数据
     name:&#39;张三&#39;,
     age: 18,
     job:&amp;#123;
        type: &#39;前端工程师&#39;,
        salary:&#39;30k&#39;,
        a:&amp;#123;
            b:&amp;#123;
                c:111
            &amp;#125;
        &amp;#125;
     &amp;#125;
   &amp;#125;)

   // 也可以用它修改数组
 //  let arr = reactive([&#39;哈哈&#39;,&#39;拉拉&#39;,&#39;也有&#39;,&#39;尽量&#39;,&#39;可以&#39;])
 //  arr[0] = &#39;爷爷&#39;

   // 方法

   function changInfo()&amp;#123;            // 用了reactive之后，可以直接不用value来修改，直接.的方式
      person.name = &#39;李四&#39;
      person.age = 48 
      person.job.type =&#39;UI工程师&#39;
      person.job.salary = &#39;40k&#39;
      person.job.a.b.c = 666
   &amp;#125;



   // 返回一个对象 返回之后才能用里面的东西 (常用)
   return &amp;#123;
   person,
  changInfo

   &amp;#125;

   // 返回一个函数 (渲染函数,了解) 它返回的东西会整个的替换掉该组件中所有的内容 
   // 用这个的话注意上面还要引用
//    return ()=&amp;gt; h(&#39;h1&#39;,&#39;哈哈哈&#39;)
  &amp;#125;
&amp;#125;
&amp;lt;/script&amp;gt;

&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;vue3-中添加和删除属性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vue3-中添加和删除属性&#34;&gt;#&lt;/a&gt; vue3 中添加和删除属性&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;script&amp;gt;
    // 这里的一切操作都是在用了 reactive 的前提下

    // 添加数据
    person.sex = &#39;男&#39;   // 直接这样写属性里面没有的 就是添加了

    // 删除属性
    delete person.name  // 删除person里面的name属性

    &amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;4vue30中的响应式原理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4vue30中的响应式原理&#34;&gt;#&lt;/a&gt; 4.Vue3.0 中的响应式原理&lt;/h2&gt;
&lt;h3 id=&#34;vue2x的响应式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vue2x的响应式&#34;&gt;#&lt;/a&gt; vue2.x 的响应式&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;实现原理：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;对象类型：通过 &lt;code&gt;Object.defineProperty()&lt;/code&gt;  对属性的读取、修改进行拦截（数据劫持）。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数组类型：通过重写更新数组的一系列方法来实现拦截。（对数组的变更方法进行了包裹）。&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Object&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;defineProperty&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;data&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;count&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存在问题：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;新增属性、删除属性，界面不会更新。&lt;/li&gt;
&lt;li&gt;直接通过下标修改数组，界面不会自动更新。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;vue30的响应式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vue30的响应式&#34;&gt;#&lt;/a&gt; Vue3.0 的响应式&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;实现原理:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;通过 Proxy（代理）:  拦截对象中任意属性的变化，包括：属性值的读写、属性的添加、属性的删除等。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通过 Reflect（反射）:  对源对象的属性进行操作。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;MDN 文档中描述的 Proxy 与 Reflect：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Proxy：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kZXZlbG9wZXIubW96aWxsYS5vcmcvemgtQ04vZG9jcy9XZWIvSmF2YVNjcmlwdC9SZWZlcmVuY2UvR2xvYmFsX09iamVjdHMvUHJveHk=&#34;&gt;https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Proxy&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Reflect：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kZXZlbG9wZXIubW96aWxsYS5vcmcvemgtQ04vZG9jcy9XZWIvSmF2YVNjcmlwdC9SZWZlcmVuY2UvR2xvYmFsX09iamVjdHMvUmVmbGVjdA==&#34;&gt;https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Reflect&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Proxy&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;data&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 拦截读取属性值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; Reflect&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;// 拦截设置属性值或添加新属性&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; Reflect&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;// 拦截删除属性&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;deleteProperty&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; Reflect&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;deleteProperty&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; prop&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;proxy&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;tom&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;5reactive对比ref&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5reactive对比ref&#34;&gt;#&lt;/a&gt; 5.reactive 对比 ref&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;从定义数据角度对比：
&lt;ul&gt;
&lt;li&gt;ref 用来定义：&amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 基本类型数据 &amp;lt;/strong&amp;gt;。&lt;/li&gt;
&lt;li&gt;reactive 用来定义：&amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 对象（或数组）类型数据 &amp;lt;/strong&amp;gt;。&lt;/li&gt;
&lt;li&gt;备注：ref 也可以用来定义 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 对象（或数组）类型数据 &amp;lt;/strong&amp;gt;, 它内部会自动通过 &lt;code&gt;reactive&lt;/code&gt;  转为 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 代理对象 &amp;lt;/strong&amp;gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;从原理角度对比：
&lt;ul&gt;
&lt;li&gt;ref 通过 &lt;code&gt;Object.defineProperty()&lt;/code&gt;  的 &lt;code&gt;get&lt;/code&gt;  与 &lt;code&gt;set&lt;/code&gt;  来实现响应式（数据劫持）。&lt;/li&gt;
&lt;li&gt;reactive 通过使用 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt;Proxy&amp;lt;/strong &amp;gt; 来实现响应式（数据劫持）, 并通过 &amp;lt; strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt;Reflect&amp;lt;/strong &amp;gt; 操作 &amp;lt; strong style=&amp;quot;color:orange&amp;quot;&amp;gt; 源对象 &amp;lt;/strong &amp;gt; 内部的数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;从使用角度对比：
&lt;ul&gt;
&lt;li&gt;ref 定义的数据：操作数据 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 需要 &amp;lt;/strong&amp;gt; &lt;code&gt;.value&lt;/code&gt; ，读取数据时模板中直接读取 &amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 不需要 &amp;lt;/strong&amp;gt; &lt;code&gt;.value&lt;/code&gt; 。&lt;/li&gt;
&lt;li&gt;reactive 定义的数据：操作数据与读取数据：&amp;lt;strong style=&amp;quot;color:#DD5145&amp;quot;&amp;gt; 均不需要 &amp;lt;/strong&amp;gt; &lt;code&gt;.value&lt;/code&gt; 。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;6setup的两个注意点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6setup的两个注意点&#34;&gt;#&lt;/a&gt; 6.setup 的两个注意点&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;setup 执行的时机&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在 beforeCreate 之前执行一次，this 是 undefined。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;setup 的参数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;props：值为对象，包含：组件外部传递过来，且组件内部声明接收了的属性。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;context：上下文对象&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;attrs: 值为对象，包含：组件外部传递过来，但没有在 props 配置中声明的属性，相当于  &lt;code&gt;this.$attrs&lt;/code&gt; 。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;slots: 收到的插槽内容，相当于  &lt;code&gt;this.$slots&lt;/code&gt; 。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;emit: 分发自定义事件的函数，相当于  &lt;code&gt;this.$emit&lt;/code&gt; 。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码实例&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;// App.vue组件
&amp;lt;template&amp;gt;
	&amp;lt;Demo @hello=&amp;quot;showHelloMsg&amp;quot; msg=&amp;quot;你好啊&amp;quot; school=&amp;quot;尚硅谷&amp;quot;&amp;gt;
		&amp;lt;template v-slot:qwe&amp;gt;
			&amp;lt;span&amp;gt;尚硅谷&amp;lt;/span&amp;gt;
		&amp;lt;/template&amp;gt;
		&amp;lt;template v-slot:asd&amp;gt;
			&amp;lt;span&amp;gt;尚硅谷&amp;lt;/span&amp;gt;
		&amp;lt;/template&amp;gt;
	&amp;lt;/Demo&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
	import Demo from &#39;./components/Demo&#39;
	export default &amp;#123;
		name: &#39;App&#39;,
		components:&amp;#123;Demo&amp;#125;,
		setup()&amp;#123;
			function showHelloMsg(value)&amp;#123;
				alert(`你好啊，你触发了hello事件，我收到的参数是:$&amp;#123;value&amp;#125;！`)
			&amp;#125;
			return &amp;#123;
				showHelloMsg
			&amp;#125;
		&amp;#125;
	&amp;#125;
&amp;lt;/script&amp;gt;

// 子组件
&amp;lt;template&amp;gt;
	&amp;lt;h1&amp;gt;一个人的信息&amp;lt;/h1&amp;gt;
	&amp;lt;h2&amp;gt;姓名：&amp;#123;&amp;#123;person.name&amp;#125;&amp;#125;&amp;lt;/h2&amp;gt;
	&amp;lt;h2&amp;gt;年龄：&amp;#123;&amp;#123;person.age&amp;#125;&amp;#125;&amp;lt;/h2&amp;gt;
	&amp;lt;button @click=&amp;quot;test&amp;quot;&amp;gt;测试触发一下Demo组件的Hello事件&amp;lt;/button&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
	import &amp;#123;reactive&amp;#125; from &#39;vue&#39;
	export default &amp;#123;
		name: &#39;Demo&#39;,
		props:[&#39;msg&#39;,&#39;school&#39;],
		emits:[&#39;hello&#39;],
		setup(props,context)&amp;#123;
			// console.log(&#39;---setup---&#39;,props)
			// console.log(&#39;---setup---&#39;,context)
			// console.log(&#39;---setup---&#39;,context.attrs) //相当与Vue2中的$attrs
			// console.log(&#39;---setup---&#39;,context.emit) //触发自定义事件的。
			console.log(&#39;---setup---&#39;,context.slots) //插槽
			//数据
			let person = reactive(&amp;#123;
				name:&#39;张三&#39;,
				age:18
			&amp;#125;)

			//方法
			function test()&amp;#123;
				context.emit(&#39;hello&#39;,666)
			&amp;#125;

			//返回一个对象（常用）
			return &amp;#123;
				person,
				test
			&amp;#125;
		&amp;#125;
	&amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;7计算属性与监视&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7计算属性与监视&#34;&gt;#&lt;/a&gt; 7. 计算属性与监视&lt;/h2&gt;
&lt;h3 id=&#34;1computed函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1computed函数&#34;&gt;#&lt;/a&gt; 1.computed 函数&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;与 Vue2.x 中 computed 配置功能一致&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写法&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;computed&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;vue&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;Demo&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;setup&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;     &lt;span class=&#34;token comment&#34;&gt;// 数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; person  &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;reactive&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;// 全对象式数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;     &lt;span class=&#34;token literal-property property&#34;&gt;firstName&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;张&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;     &lt;span class=&#34;token literal-property property&#34;&gt;lastName&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;三&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 计算属性 —— 简写&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; fullName &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;computed&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;           &lt;span class=&#34;token comment&#34;&gt;// 直接在 person 上追加一个新属性 在调用 computed () 方法&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;firstName &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;-&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;lastName&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;// 计算属性 —— 完整&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; fullName &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;computed&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;firstName &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;-&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;lastName&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token function&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; nameArr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; value&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;split&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;-&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;firstName &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; nameArr&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            person&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;lastName &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; nameArr&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2watch函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2watch函数&#34;&gt;#&lt;/a&gt; 2.watch 函数&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;与 Vue2.x 中 watch 配置功能一致&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;两个小 “坑”：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;监视 reactive 定义的响应式数据时：oldValue 无法正确获取、强制开启了深度监视（deep 配置失效）。&lt;/li&gt;
&lt;li&gt;监视 reactive 定义的响应式数据中某个属性时：deep 配置有效。&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;ref&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; watch&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;vue&#39;&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;// 记得引入&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;Demo&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token function&#34;&gt;setup&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token comment&#34;&gt;// 数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token key